// 03 · Normalize — read original webhook (Set node must not wipe body)
const webhook = $('01 · Receive Order Webhook').item.json;
const body = webhook.body ?? webhook;
const loc =
  $('02 · Set GHL Location ID').item.json.locationId ||
  'uc3GK4buCjDTCkedqWyy';

const customer = body.customer || {};
const order = body.order || {};
const phone = (
  customer.phone_e164 ||
  customer.phone ||
  customer.phone_raw ||
  ''
)
  .toString()
  .trim();
const rawName = (customer.name || '').toString().trim();
const firstName = rawName.split(/\s+/)[0] || 'Guest';
const lastName = rawName.split(/\s+/).slice(1).join(' ') || 'Caller';

const orderType = (order.order_type || '').toString().toLowerCase();
const channel = (body.channel || '').toString().toLowerCase() || null;
const status = (order.status || 'placed').toString().toLowerCase();
const lastOrderId =
  order.clover_order_id || body.session_id || body.event_id || null;
const total = order.total ?? null;

const items = Array.isArray(order.items) ? order.items : [];
const summary =
  items.length > 0
    ? items
        .map((i) => {
          const qty = i.qty ?? i.quantity ?? 1;
          const name = i.name || 'item';
          return `${qty}x ${name}`;
        })
        .join(', ')
    : null;

const tagsToAdd = ['voice-order', 'order-placed'];
if (orderType === 'pickup') tagsToAdd.push('pickup');
if (orderType === 'delivery') tagsToAdd.push('delivery');

// Contact custom field IDs — plan §7.1
const customFields = [
  { id: '0QK5vxB5ntrYG44o33Gn', field_value: lastOrderId != null ? String(lastOrderId) : '' },
  { id: 'nl3jIwfxyUgQHPRlbGZl', field_value: orderType || '' },
  { id: 'Q59Rb7F84BNHvrL1gzOJ', field_value: status || 'placed' },
  {
    id: 'IeLzeT4I8xitx3Jvk9mQ',
    field_value: total != null && total !== '' ? Number(total) : '',
  },
  { id: 'FyLZbBVUDD9TzY7LXlm4', field_value: summary || '' },
  { id: 'UUqkRGbEl5HjS5Sd2eIz', field_value: channel || '' },
].filter((f) => f.field_value !== '' && f.field_value !== null && f.field_value !== undefined);

const upsertBody = {
  locationId: loc,
  phone,
  firstName,
  lastName,
  source: 'Voice Agent',
  customFields,
};

return {
  json: {
    locationId: loc,
    event: body.event || 'unknown',
    event_id: body.event_id || null,
    session_id: body.session_id || null,
    channel,
    phone,
    firstName,
    lastName,
    fullName: rawName || null,
    order_type: orderType || null,
    clover_order_id: order.clover_order_id || null,
    order_total: total,
    order_summary: summary,
    tagsToAdd,
    upsertBody,
    hasPhone: phone.length >= 7,
    raw: body,
  },
};

// 08 · Prepare opportunity payload — plan §7.2
const norm = $('03 · Normalize Order Payload').item.json;
const upsert = $('05 · GHL · Upsert Contact + Fields').item.json;
const contactId = upsert.contact?.id || null;

const PIPELINE_ID = 'wCQVOwUah69xD6KHFrsi';
const STAGE_ABANDONED = 'ed4e4d7b-7a77-4e86-9c98-5a4204a046ac';
const STAGE_PLACED = 'a6c71988-47c0-4f13-8a2b-40b784a9a72f';
const CF_EVENT_ID = 'ebYtqePmkjxB2BFjaEtJ';
const CF_CLOVER = 'mqQZGfXEM7Ixbfcpbeej';
const CF_SESSION = 'urTkDJuILkxhG4942CmU';
const CF_SUMMARY = 'zH1m3iD6sNuy8y22uqMa';

const typePart = norm.order_type || 'order';
const namePart = norm.firstName || 'Guest';
const summaryPart = (norm.order_summary || '').toString();
let oppName = `${typePart} · ${namePart}`;
if (summaryPart) oppName += ` · ${summaryPart}`;
if (oppName.length > 80) oppName = oppName.slice(0, 77) + '...';

const oppCustomFields = [
  { id: CF_EVENT_ID, field_value: norm.event_id != null ? String(norm.event_id) : '' },
  { id: CF_CLOVER, field_value: norm.clover_order_id != null ? String(norm.clover_order_id) : '' },
  { id: CF_SESSION, field_value: norm.session_id != null ? String(norm.session_id) : '' },
  { id: CF_SUMMARY, field_value: summaryPart },
].filter((f) => f.field_value !== '' && f.field_value !== null && f.field_value !== undefined);

const monetary =
  norm.order_total != null && norm.order_total !== ''
    ? Number(norm.order_total)
    : undefined;

const createBody = {
  pipelineId: PIPELINE_ID,
  locationId: norm.locationId,
  name: oppName,
  pipelineStageId: STAGE_PLACED,
  status: 'open',
  contactId,
  customFields: oppCustomFields,
};
if (monetary != null && !Number.isNaN(monetary)) {
  createBody.monetaryValue = monetary;
}

const updateBody = {
  name: oppName,
  pipelineId: PIPELINE_ID,
  pipelineStageId: STAGE_PLACED,
  status: 'open',
  customFields: oppCustomFields,
};
if (monetary != null && !Number.isNaN(monetary)) {
  updateBody.monetaryValue = monetary;
}

return {
  json: {
    contactId,
    session_id: norm.session_id || null,
    pipelineId: PIPELINE_ID,
    stageAbandonedId: STAGE_ABANDONED,
    stagePlacedId: STAGE_PLACED,
    locationId: norm.locationId,
    createBody,
    updateBody,
    skipOpp: !contactId,
  },
};

// 10 · Resolve create vs move Abandoned→Placed
const prep = $('08 · Prepare Opportunity').item.json;
const search = $input.item.json;
const sessionId = prep.session_id ? String(prep.session_id) : null;
const CF_SESSION = 'urTkDJuILkxhG4942CmU';

const list = search.opportunities || search.data?.opportunities || [];
let matchId = null;
if (sessionId && Array.isArray(list)) {
  for (const opp of list) {
    const cfs = opp.customFields || opp.customField || [];
    const hit = cfs.find(
      (c) =>
        (c.id === CF_SESSION || c.fieldKey === 'opportunity.session_id' || c.key === 'opportunity.session_id') &&
        String(c.fieldValue ?? c.field_value ?? c.value ?? '') === sessionId
    );
    if (hit) {
      matchId = opp.id;
      break;
    }
  }
}

const moveExisting = Boolean(matchId) && !prep.skipOpp;
const createNew = !moveExisting && !prep.skipOpp;

return {
  json: {
    ...prep,
    matchOpportunityId: matchId,
    moveExisting,
    createNew,
    searchCount: Array.isArray(list) ? list.length : 0,
  },
};

const norm = $('03 · Normalize Order Payload').first().json;
const upsert = $('05 · GHL · Upsert Contact + Fields').first().json;
const resolve = $('10 · Resolve Opp Action').first().json;
const oppResp = $input.first().json;
const status = upsert.statusCode ?? upsert.status ?? null;
const ok =
  status === undefined ||
  status === null ||
  (Number(status) >= 200 && Number(status) < 300);

const opp =
  oppResp.opportunity ||
  oppResp.data?.opportunity ||
  oppResp;
const oppId = opp?.id || resolve.matchOpportunityId || null;
const oppHttp = oppResp.statusCode ?? oppResp.status ?? null;

return {
  json: {
    ok: true,
    event: norm.event,
    event_id: norm.event_id,
    phone: norm.phone,
    tags: norm.tagsToAdd,
    order_summary: norm.order_summary,
    ghl_http_status: status,
    ghl_ok: ok,
    ghl_contact_id: upsert.contact?.id || null,
    sms_rearm: 'removed order-placed then re-added',
    opp_action: resolve.moveExisting ? 'moved_abandoned_to_placed' : resolve.createNew ? 'created_placed' : 'skipped',
    opp_id: oppId,
    opp_http_status: oppHttp,
  },
};
